### 3. print_int and parse_int Implementations
From `/Users/mike/github/sw-embed/sw-cor24-apl/src/num.h`:

**print_int** (uses APL underscore-negative convention):
```c
void print_int(int n) {
    if (n < 0) {
        putchar(95);  // underscore
        n = 0 - n;
    }
    if (n == 0) {
        putchar(48);
        return;
    }
    char buf[8];
    int i = 0;
    while (n > 0) {
        buf[i] = 48 + n % 10;
        n = n / 10;
        i++;
    }
    while (i > 0) {
        i--;
        putchar(buf[i]);
    }
}
```

**parse_int** (handles APL underscore-negative convention):
```c
int parse_int(char *s, int start, int *end) {
    int i = start;
    int neg = 0;
    int val = 0;
    int got = 0;

    // Check for underscore-negative prefix
    if (s[i] == 95) {
        neg = 1;
        i++;
    }

    // Parse digits
    while (s[i] >= 48 && s[i] <= 57) {
        val = val * 10 + (s[i] - 48);
        i++;
        got = 1;
    }

    if (got == 0) {
        // No digits consumed
        *end = start;
        return 0;
    }

    *end = i;
    if (neg) {
        return 0 - val;
    }
    return val;
}
```

