```c
int io_getline(char *buf, int len) {
    int pos = 0;
    int maxpos = len - 1;

    while (1) {
        int ch = getchar();

        if (ch == 10 || ch == 13) {
            // Newline -- terminate
            putchar(10);
            buf[pos] = 0;
            return pos;
        }

        if (ch == 8 || ch == 127) {
            // Backspace or DEL -- erase last char
            if (pos > 0) {
                pos--;
                putchar(8);   // BS
                putchar(32);  // space
                putchar(8);   // BS
            }
        } else if (ch >= 32 && pos < maxpos) {
            // Printable character
            buf[pos] = ch;
            pos++;
            putchar(ch);
        }
        // Ignore other control chars and overflow
    }
}
```

### 5. UART Status Register Bits
- **Bit 7 (0x80)**: TX busy flag - set when transmitter is busy
- **Bit 0 (0x01)**: RX data ready flag - set when data is available to read

